1	\chapter{Geometric and height infrastructure}
2	\label{chap:basic}
3	
4	% archon:covers MR4276287UniformityInMordellLangForCurves/Basic.lean
5	
6	This chapter packages the geometric and height-theoretic input used by the
7	later counting arguments.
8	
9	\section{Ambient setup}
10	
11	\begin{definition}[Ambient moduli and height data]
12	  \label{def:ambient_setup}
13	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.ambientSetup}
14	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
15	  % SOURCE QUOTE: "There exists a universal curve $\mathfrak{C}_g$ over $\mathbb{M}_g$,  it is smooth and proper over $\mathbb{M}_g$ and its fibers are smooth curves of genus $g$."
16	  % SOURCE QUOTE PROOF: This section fixes the universal curve, the universal abelian variety, and the height package used throughout the chapter.
17	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
18	  Fix \(g \ge 2\). Let \(\mathbb{M}_g\) be the fine moduli space of smooth
19	  genus-\(g\) curves with level structure, let \(\mathfrak{C}_g \to \mathbb{M}_g\)
20	  be the universal curve, and let \(\mathfrak{A}_g \to \mathbb{A}_g\) be the
21	  universal principally polarized abelian variety with the chosen projective
22	  embeddings. Fix the ample line bundles and the associated height functions on
23	  the compactifications, together with the fiberwise Néron--Tate height on the
24	  universal abelian family.
25	\end{definition}
26	
27	\begin{lemma}[Height comparison on the moduli side]
28	  \label{lem:moduli_height_comparison}
29	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.moduliHeightComparison}
30	  \uses{def:ambient_setup}
31	  % SOURCE: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
32	  % SOURCE QUOTE: "If $k=\IQbar$ and as described in $\mathsection\ref{SubsectionHeight}$ we obtain two height functions, the restriction of the Weil height $h\colon \overline{S}(\IQbar)\rightarrow \IR$ and the N\'eron--Tate height $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow \IR$."
33	  % SOURCE QUOTE PROOF: The paper compares these heights after fixing a projective embedding on the moduli side and reading the induced height along the Torelli map.
34	  \textit{Source: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex).}
35	  The chosen projective height on the moduli space and the height induced by
36	  \(\mathbb{A}_g\) are comparable up to affine linear error terms along the
37	  Torelli map.
38	\end{lemma}
