106	\section{Height inequality}
107	
108	\begin{definition}[Non-degenerate subvariety]
109	  \label{def:nondegenerate_app}
110	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.nonDegenerate}
111	  \uses{prop:betti_map_app}
112	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
113	  % SOURCE QUOTE: "An irreducible subvariety \(X\) of \(\cA\) is said to be non-degenerate if there exists an open non-empty subset \(\Delta\) ... such that ... \(\max_{x \in X^{\mathrm{sm}}(\IC) \cap \cA_{\Delta}} \mathrm{rank}_{\IR} (\mathrm{d}b_{\Delta}|_{X^{\mathrm{sm,an}}})_x = 2\dim X\)."
114	  % SOURCE QUOTE PROOF: This restates the appendix criterion in the language of local Betti rank on the smooth locus.
115	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
116	  An irreducible subvariety is non-degenerate if some local Betti map has full
117	  real rank \(2\dim X\) on a smooth point of the analytification.
118	\end{definition}
119	
120	\begin{proposition}[Auxiliary height inequality]
121	  \label{prop:aux_ht_ineq}
122	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.auxHeightInequality}
123	  \uses{prop:betti_form,thm:silverman_tate,def:nondegenerate_app,lem:graph_construction}
124	  % SOURCE: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex)
125	  % SOURCE QUOTE: "Suppose \(\an{X}\) contains a smooth point at which \(\omega|_{\sman{X}}^{\wedge d} >0\). Then there exists a constant \(c_1 > 0\) ... \(h([N]P) \ge c_1 N^2 h(\pi(P)) - c_2(N)\)."
126	  % SOURCE QUOTE PROOF: The proof studies the graph of multiplication-by-\(N\), uses the Betti form to force positivity there, and then reads off a height lower bound.
127	  \textit{Source: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex).}
128	  The graph construction turns the estimate into a comparison of intersection
129	  numbers on the projective closure \(\overline{X_N}\). Siu's criterion then
130	  converts the positivity of the Betti form into a lower bound for the
131	  projective height of \([N]P\) in terms of the height of the base point.
132	\end{proposition}
133	
134	\begin{lemma}[Graph construction for the height inequality]
135	  \label{lem:graph_construction}
136	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.graphConstruction}
137	  \uses{def:ambient_setup}
138	  % SOURCE: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex)
139	  % SOURCE QUOTE: "For each \(N \in \IN\), we work with \(X_N \subseteq \cA\times_S \cA\), the graph of \([N] \colon \cA \rightarrow \cA\), and its Zariski closure \(\overline{X_N}\) in \(\overline{\cA}\times_{\overline{S}}\overline{\cA}\)."
140	  % SOURCE QUOTE PROOF: This is the projective closure on which the auxiliary inequality is evaluated.
141	  \textit{Source: Section 4 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneq.tex).}
142	  For each \(N\), the graph of multiplication-by-\(N\) on the family produces a
143	  projective closure \(\overline{X_N}\) on which the relevant heights become the
144	  heights associated to the line bundles \(\mathcal F\) and \(\mathcal M\).
145	\end{lemma}
146	
147	\begin{theorem}[Height inequality under the paper's hypotheses]
148	  \label{thm:ht_inequality}
149	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.heightInequality}
150	  \uses{prop:aux_ht_ineq,thm:silverman_tate,lem:graph_construction}
151	  % SOURCE: Section 5 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/NTbase.tex)
152	  % SOURCE QUOTE: "There exists a constant \(c_1>0\) ... \(\hat{h}_{\mathcal{A}}(P) \ge c_1 N^2 h(\pi(P)) - c_2(N)\)."
153	  % SOURCE QUOTE PROOF: This is the canonical-height form of the auxiliary estimate after the Silverman--Tate comparison is inserted.
154	  \textit{Source: Section 5 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/NTbase.tex).}
155	  After one fixed power of \(2\) is chosen, the canonical height on the total
156	  space is bounded below by a positive multiple of the height on the base on a
157	  dense open subset of any non-degenerate subvariety.
158	\end{theorem}
159	
160	\begin{theorem}[Full height inequality]
161	  \label{thm:ht_inequality_full}
162	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.heightInequalityFull}
163	  \uses{prop:betti_map_app,lem:betti_rank_zar_open_app,def:nondegenerate_app,thm:ht_inequality}
164	  % SOURCE: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex)
165	  % SOURCE QUOTE: "Let \(X\) be an irreducible subvariety of \(\cA\) ... Then there exist constants \(c_1>0\) and \(c_2\ge 0\) and a Zariski open dense subset \(U\) of \(X\) with \(\hat{h}_{\cA,\cL}(P) \ge c_1 h_{\overline{S},\cM}( \pi(P) ) - c_2\)."
166	  % SOURCE QUOTE PROOF: The appendix removes the extra Hyp assumptions by passing through the general Betti-map setup and then shrinking to a dense open subset.
167	  \textit{Source: Appendix B of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/HtIneqFinalVer.tex).}
168	  The appendix first enlarges the Betti-map input to arbitrary regular bases and
169	  then performs a six-step devissage: close up \(X\), replace the base by the
170	  image of \(X\), pass to a regular cover carrying level structure and a
171	  principal polarization, and finally invoke the height inequality already
172	  proved under the paper's hypotheses. The result is the same lower bound for
173	  the canonical height on a dense open subset of any non-degenerate subvariety.
174	\end{theorem}
