176	\section{Counting lemmas}
177	
178	\begin{lemma}[Uniform degree bound]
179	  \label{lem:uniform_degree_bound}
180	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.uniformDegreeBound}
181	  \uses{def:ambient_setup}
182	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
183	  % SOURCE QUOTE: "There exists a constant \(c\) such that ... \(\deg(\mathfrak{C}_s-P) \le c\) ... and \(h(\mathfrak{C}_s-P_s) \le c \max\{1, h_{\overline{\mathbb{A}_g},\cM}(\tau(s))\}\)."
184	  % SOURCE QUOTE PROOF: The section bounds both the projective degree and the moduli height of the translated fibers uniformly in the base point.
185	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
186	  Translates of a fixed fiber curve have uniformly bounded projective degree, and
187	  one translate in each fiber has height controlled by the moduli point.
188	\end{lemma}
189	
190	\begin{theorem}[Non-degeneracy of the Faltings--Zhang image]
191	  \label{thm:nondeg_for_bd}
192	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.faltingsZhangNondegenerate}
193	  \uses{def:ambient_setup,def:nondegenerate_app}
194	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
195	  % SOURCE QUOTE: "Let \(S\) be an irreducible variety with a (not necessarily dominant) quasi-finite morphism \(S \rightarrow \mathbb{M}_g\). Assume \(g \ge 2\) and \(M \ge 3g-2\). Then \(\mathscr{D}_M( \mathfrak{C}_S^{[M+1]} )\) ... is non-degenerate."
196	  % SOURCE QUOTE PROOF: Gao's theorem gives the needed non-degeneracy once the fiber power is large enough.
197	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
198	  For sufficiently large fiber power, Gao's theorem shows that the Faltings--Zhang
199	  image of the universal curve family is non-degenerate.
200	\end{theorem}
201	
202	\begin{lemma}[Quantitative Vojta--Mumford estimate]
203	  \label{lem:vojtamumford}
204	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.vojtaMumford}
205	  \uses{thm:silverman_tate,lem:uniform_degree_bound}
206	  % SOURCE: Section 8 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/RatPt.tex)
207	  % SOURCE QUOTE: "Let \(C\) be an irreducible curve in \(A\). There exists a constant \(c=c(n,\deg C)\ge 1\) ... \# \{P \in C(\IQbar)\cap \Gamma : \hat h_{L}(P) > c\max\{1,h(C),c_{\mathrm{NT}},h_1\} \} \le c^\rho."
208	  % SOURCE QUOTE PROOF: The estimate is the large-points part of the Vojta--Mumford method and depends on the subgroup rank through the exponent.
209	  \textit{Source: Section 8 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/RatPt.tex).}
210	  A curve inside an abelian variety contributes at most exponentially many points
211	  of large canonical height, with the exponent controlled by the subgroup rank.
212	\end{lemma}
213	
214	\begin{lemma}[N-Alon combinatorial lemma]
215	  \label{lem:NAlon}
216	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.nAlon}
217	  \uses{def:ambient_setup}
218	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
219	  % SOURCE QUOTE: "Let \(C \subset \IP_k^n\) be an irreducible curve ... Then there exists a number \(B\), depending only on \(M, \deg C,\) and \(\deg Z\), ... if \(\Sigma \subset C(k)\) has cardinality \(\ge B\), then \(\Sigma^M \not\subseteq Z(k)\)."
220	  % SOURCE QUOTE PROOF: This is the product-avoidance input used to keep large subsets of a curve from collapsing into a proper closed set.
221	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
222	  Large enough subsets of a curve cannot have all \(M\)-fold products trapped in
223	  a fixed proper closed subset of the ambient product.
224	\end{lemma}
225	
226	\begin{lemma}[Packets alternative]
227	  \label{lem:packets_alternative3}
228	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.packetsAlternative}
229	  \uses{def:ambient_setup}
230	  % SOURCE: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
231	  % SOURCE QUOTE: "If \(Z\) is an irreducible Zariski closed and proper subset of \(\mathscr{D}_M(C^{M+1})\), then \(\#\{ P \in C(\overline{\IQ}) : (C-P)^M \subset Z \} \le 84(g-1)\)."
232	  % SOURCE QUOTE PROOF: Hurwitz theory bounds the number of points whose packet condition lands in a fixed proper closed subset.
233	  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
234	  A proper closed condition on the Faltings--Zhang image can only hold for
235	  uniformly many base points on a curve of genus at least \(2\).
236	\end{lemma}
237	
238	\begin{proposition}[Points on curves are sparse]
239	  \label{prop:alg_pt_far}
240	  \lean{MR4276287UniformityInMordellLangForCurves.Basic.algPointsFar}
241	  \uses{thm:nondeg_for_bd,thm:ht_inequality_full,lem:uniform_degree_bound,lem:NAlon,lem:packets_alternative3}
242	  % SOURCE: Section 7 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/DistanceCurve.tex)
243	  % SOURCE QUOTE: "There exist positive constants \(c_1, c_2, c_3, c_4\) ... either \(P \in \Xi_s\), or \(\#\{Q \in \mathfrak{C}_s(\IQbar) : \hat{h}(Q-P) \le h_{\overline{\mathbb{A}_g},\cM}(\tau(s))/c_3\} < c_4\)."
244	  % SOURCE QUOTE PROOF: This is the distance alternative obtained by combining the non-degeneracy input, the height inequalities, and the counting lemmas.
245	  \textit{Source: Section 7 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/DistanceCurve.tex).}
246	  For a family of genus-\(g\) curves with large moduli height, every point is
247	  either exceptional or has only uniformly boundedly many nearby points in the
248	  canonical metric.
249	\end{proposition}
